Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** from the `Microsoft.AspNetCore.Mvc.Testing` package. It boots your app in-process with a test server — no real port needed.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### Example test class

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (stateful session via Mcp-Session-Id header)
        var init = new { jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new { protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" } } };
        var initResp = await _client.PostAsJsonAsync("/mcp", init);
        var sessionId = initResp.Headers
            .GetValues("Mcp-Session-Id").First();

        // List tools
        var listReq = new HttpRequestMessage(HttpMethod.Post, "/mcp")
        {
            Content = JsonContent.Create(new
            {
                jsonrpc = "2.0", id = 2, method = "tools/list"
            })
        };
        listReq.Headers.Add("Mcp-Session-Id", sessionId);

        var resp = await _client.SendAsync(listReq);
        resp.EnsureSuccessStatusCode();

        var body = await resp.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real port** | `WebApplicationFactory` uses an in-memory `TestServer` |
| **Session tracking** | Capture `Mcp-Session-Id` from `initialize` and pass it on subsequent requests |
| **Protocol** | MCP Streamable HTTP = JSON-RPC POST to your MCP endpoint |
| **`Program` visibility** | Add `<InternalsVisibleTo Include="YourTestProject" />` in the server's `.csproj`, or use a `public partial class Program { }` marker |

This gives you full HTTP-stack coverage (middleware, routing, serialization) while staying entirely in-process.
